I can help you narrow it down with a safe check – no file contents will be exposed. Run this PowerShell command for each file to see its size and first few bytes (header signature):

```powershell
$files = @(
    "C:\Users\Me\Documents\Electrum\wallets\default_wallet",
    "D:\Backups\old_stuff\backup.dat",
    "D:\Backups\old_stuff\wallet.json"
)
foreach ($f in $files) {
    if (Test-Path $f) {
        $size = (Get-Item $f).Length
        $bytes = [System.IO.File]::ReadAllBytes($f)
        $header = ($bytes[0..7] | ForEach-Object { $_.ToString("X2") }) -join " "
        Write-Host "File: $f"
        Write-Host "Size: $size bytes"
        Write-Host "First 8 bytes (hex): $header"
        if ($bytes.Length -ge 4 -and $bytes[0] -eq 0x42 -and $bytes[1] -eq 0x49 -and $bytes[2] -eq 0x45 -and $bytes[3] -eq 0x31) {
            Write-Host "-> BIE1 (Encrypted Electrum wallet)"
        } elseif ($bytes[0] -eq 0x7B) { # '{' start of JSON
            # Check for "seed_version" or "wallet_type" quickly (first 2KB)
            $text = [System.Text.Encoding]::UTF8.GetString($bytes, 0, [Math]::Min(2048, $bytes.Length))
            if ($text.Contains("seed_version") -or $text.Contains("wallet_type")) {
                Write-Host "-> Electrum JSON wallet (likely unencrypted)"
            } else {
                Write-Host "-> JSON file (unknown type)"
            }
        } else {
            Write-Host "-> Unknown format"
        }
        Write-Host "---"
    } else {
        Write-Host "File not found: $f"
    }
}
```

